// Process incoming content (text from frontend or extracted file text from backend)
const webhook = $('Webhook').first().json.body;

const document = webhook.content || '';
const userId = webhook.user_id || '';
const agentId = webhook.agent_id || 'personal_assistant';
const category = webhook.category || 'custom_instructions';
const source = webhook.type === 'file' ? 'file_upload' : 'agent_settings';

if (!document.trim()) {
  throw new Error('No content provided');
}

return {
  json: {
    user_id: userId,
    agent_id: agentId,
    category: category,
    document: document.trim(),
    source: source
  }
};

const trigger = $('Process Content').first().json;
const inserted = $input.first().json;

return {
  json: {
    success: true,
    action: 'knowledge_saved',
    user_id: trigger.user_id,
    agent_id: trigger.agent_id,
    category: trigger.category,
    source: trigger.source,
    inserted_id: inserted?.id || null,
    timestamp: new Date().toISOString()
  }
};
